import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;

public class LoginManager {
    private static final String PREFS_NAME = "LoginPrefs";
    private static final String EMAIL_KEY = "email";
    private static final String TOKEN_KEY = "token";

    public void saveCredentials(Context context, String email, String token) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit().putString(EMAIL_KEY, email).putString(TOKEN_KEY, token).apply();
    }

    public boolean checkSavedCredentials(Context context, String inputEmail, String inputToken) {
        SharedPreferences prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String savedEmail = prefs.getString(EMAIL_KEY, null);
        String savedToken = prefs.getString(TOKEN_KEY, null);

        if (savedEmail != null && savedToken != null) {
            Log.d("LoginManager", "Credentials found in SharedPreferences");

            // For the sake of this prototype demo, we'll assume valid credentials are saved
            return inputEmail.equals(savedEmail) && inputToken.equals(savedToken);
        }

        return false;
    }
}